import torch
import torch.nn as nn
import torchvision.transforms as transforms
import torchvision.models as models
from flask import Flask, request, jsonify
from PIL import Image
import io
import numpy as np
import hashlib
import time

app = Flask(__name__)

device = torch.device("cuda" if torch.cuda.is_available() else "cpu")
model = models.resnet50(pretrained=True)
model = model.to(device)
model.eval()

transform = transforms.Compose([
    transforms.Resize(256),
    transforms.CenterCrop(224),
    transforms.ToTensor(),
    transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225]),
])

with open('imagenet_classes.txt', 'r') as f:
    classes = [line.strip() for line in f.readlines()]

class AdversarialDefense:
    def __init__(self):
        self.request_cache = {}
        self.cache_timeout = 60
        
    def detect_gradient_based_attack(self, image_tensor):
        image_np = image_tensor.cpu().numpy()
        gradient_magnitude = np.abs(np.gradient(image_np))
        avg_gradient = np.mean(gradient_magnitude)
        
        if avg_gradient > 0.5:
            return True
        return False
    
    def detect_high_frequency_noise(self, image_tensor):
        image_np = image_tensor.squeeze().cpu().numpy()
        fft = np.fft.fft2(image_np[0])
        fft_shift = np.fft.fftshift(fft)
        magnitude_spectrum = np.abs(fft_shift)
        
        h, w = magnitude_spectrum.shape
        center_h, center_w = h // 2, w // 2
        high_freq_region = magnitude_spectrum.copy()
        high_freq_region[center_h-20:center_h+20, center_w-20:center_w+20] = 0
        
        high_freq_energy = np.sum(high_freq_region)
        total_energy = np.sum(magnitude_spectrum)
        
        if total_energy > 0 and (high_freq_energy / total_energy) > 0.15:
            return True
        return False
    
    def input_transformation(self, image_tensor):
        bit_depth_reduction = torch.round(image_tensor * 16) / 16
        
        kernel_size = 3
        padding = kernel_size // 2
        smoothed = torch.nn.functional.avg_pool2d(
            bit_depth_reduction.unsqueeze(0), 
            kernel_size=kernel_size, 
            stride=1, 
            padding=padding
        ).squeeze(0)
        
        return smoothed
    
    def ensemble_prediction(self, image_tensor, model):
        predictions = []
        
        original_output = model(image_tensor.unsqueeze(0))
        predictions.append(original_output)
        
        transformed = self.input_transformation(image_tensor)
        transformed_output = model(transformed.unsqueeze(0))
        predictions.append(transformed_output)
        
        noise = torch.randn_like(image_tensor) * 0.01
        noisy_image = image_tensor + noise
        noisy_output = model(noisy_image.unsqueeze(0))
        predictions.append(noisy_output)
        
        avg_prediction = torch.mean(torch.stack(predictions), dim=0)
        
        variance = torch.var(torch.stack(predictions), dim=0)
        max_variance = torch.max(variance).item()
        
        return avg_prediction, max_variance
    
    def check_confidence_distribution(self, output):
        probabilities = torch.nn.functional.softmax(output, dim=1)
        top_probs, _ = torch.topk(probabilities, k=5)
        
        if top_probs[0][0] < 0.3:
            return True
        
        if top_probs[0][0] - top_probs[0][1] < 0.1:
            return True
            
        return False
    
    def rate_limit_check(self, image_hash):
        current_time = time.time()
        
        expired_keys = [k for k, v in self.request_cache.items() 
                       if current_time - v['timestamp'] > self.cache_timeout]
        for k in expired_keys:
            del self.request_cache[k]
        
        if image_hash in self.request_cache:
            request_count = self.request_cache[image_hash]['count']
            if request_count > 10:
                return True
            self.request_cache[image_hash]['count'] += 1
        else:
            self.request_cache[image_hash] = {
                'timestamp': current_time,
                'count': 1
            }
        
        return False

defense = AdversarialDefense()

@app.route('/classify', methods=['POST'])
def classify_image():
    if 'image' not in request.files:
        return jsonify({'error': 'No image provided'}), 400
    
    file = request.files['image']
    img_bytes = file.read()
    
    image_hash = hashlib.sha256(img_bytes).hexdigest()
    
    if defense.rate_limit_check(image_hash):
        return jsonify({
            'error': 'Potential adversarial attack detected',
            'reason': 'Rate limit exceeded for similar images'
        }), 403
    
    image = Image.open(io.BytesIO(img_bytes)).convert('RGB')
    
    image_tensor = transform(image).to(device)
    
    if defense.detect_gradient_based_attack(image_tensor):
        return jsonify({
            'error': 'Potential adversarial attack detected',
            'reason': 'Abnormal gradient patterns'
        }), 403
    
    if defense.detect_high_frequency_noise(image_tensor):
        return jsonify({
            'error': 'Potential adversarial attack detected',
            'reason': 'High frequency noise detected'
        }), 403
    
    with torch.no_grad():
        avg_output, variance = defense.ensemble_prediction(image_tensor, model)
        
        if variance > 0.5:
            return jsonify({
                'error': 'Potential adversarial attack detected',
                'reason': 'High prediction variance across transformations'
            }), 403
        
        if defense.check_confidence_distribution(avg_output):
            return jsonify({
                'error': 'Potential adversarial attack detected',
                'reason': 'Suspicious confidence distribution'
            }), 403
        
        probabilities = torch.nn.functional.softmax(avg_output, dim=1)
        confidence, predicted_idx = torch.max(probabilities, 1)
        
        predicted_class = classes[predicted_idx.item()]
        confidence_score = confidence.item()
    
    return jsonify({
        'predicted_class': predicted_class,
        'confidence': float(confidence_score),
        'status': 'success'
    })

